import org.apache.spark.sql.{SparkSession, DataFrame}
import org.apache.spark.sql.functions._
import scala.util.{Try, Success, Failure}
import java.util.UUID
import scala.collection.mutable

case class QueryRequest(sql: String, userId: String, requestId: String)
case class QueryResponse(requestId: String, result: Option[String], error: Option[String])

object SecureSparkQueryEngine {
  private val spark = SparkSession.builder()
    .appName("SecureSparkAnalytics")
    .config("spark.sql.adaptive.enabled", "true")
    .config("spark.sql.adaptive.coalescePartitions.enabled", "true")
    .getOrCreate()
  
  private val queryHistory = mutable.Map[String, Long]()
  private val activeUsers = mutable.Set[String]()
  
  private val ALLOWED_FUNCTIONS = Set(
    "select", "from", "where", "group", "order", "limit", "count", "sum", "avg", 
    "min", "max", "cast", "between", "in", "like", "is", "null", "and", "or", "not"
  )
  
  private val MAX_QUERY_TIME_MS = 30000L
  private val MAX_RESULT_SIZE = 100000000L // 100MB
  
  def executeQuery(request: QueryRequest): QueryResponse = {
    val startTime = System.currentTimeMillis()
    val requestId = request.requestId
    
    try {
      // Validate user
      if (!validateUser(request.userId)) {
        return QueryResponse(requestId, None, Some("Unauthorized user"))
      }
      
      // Validate query
      if (!validateQuery(request.sql)) {
        return QueryResponse(requestId, None, Some("Invalid query syntax"))
      }
      
      // Check query time limit
      if (System.currentTimeMillis() - startTime > MAX_QUERY_TIME_MS) {
        return QueryResponse(requestId, None, Some("Query timeout"))
      }
      
      // Execute query
      val df = spark.sql(request.sql)
      
      // Check result size
      val resultSize = df.rdd.count()
      if (resultSize > MAX_RESULT_SIZE) {
        return QueryResponse(requestId, None, Some("Query result too large"))
      }
      
      // Convert to JSON for response
      val resultJson = df.toJSON.collect().mkString("[", ",", "]")
      
      // Update query history
      queryHistory.put(requestId, System.currentTimeMillis())
      
      QueryResponse(requestId, Some(resultJson), None)
      
    } catch {
      case e: Exception =>
        QueryResponse(requestId, None, Some(s"Query execution failed: ${e.getMessage}"))
    }
  }
  
  private def validateUser(userId: String): Boolean = {
    userId != null && userId.nonEmpty && activeUsers.contains(userId)
  }
  
  private def validateQuery(sql: String): Boolean = {
    if (sql == null || sql.trim.isEmpty) return false
    
    val cleanSql = sql.toLowerCase().trim
    val words = cleanSql.split("\\s+").filter(_.nonEmpty)
    
    // Check for forbidden operations
    val forbiddenWords = Set("drop", "delete", "update", "insert", "create", "alter", "truncate")
    if (words.exists(forbiddenWords.contains)) return false
    
    // Check for valid SQL structure
    if (!cleanSql.startsWith("select")) return false
    
    // Basic syntax validation
    Try {
      spark.sql(sql)
    }.isSuccess
  }
  
  def registerUser(userId: String): Unit = {
    activeUsers.add(userId)
  }
  
  def unregisterUser(userId: String): Unit = {
    activeUsers.remove(userId)
  }
  
  def cleanupOldQueries(): Unit = {
    val now = System.currentTimeMillis()
    queryHistory.filterInPlace { case (_, timestamp) =>
      now - timestamp < 3600000 // Keep queries for 1 hour
    }
  }
}

object QueryAPI {
